"use strict";(self.webpackChunkdst_api_webdocs=self.webpackChunkdst_api_webdocs||[]).push([[13529],{42680:i=>{i.exports=JSON.parse('{"tag":{"label":"brain","permalink":"/dst-api-webdocs/docs/tags/brain","allTagsPath":"/dst-api-webdocs/docs/tags","count":27,"items":[{"id":"game-scripts/brains/mushgnomebrain","title":"Mushgnomebrain","description":"AI brain component that governs the behavior of the Mushgnome enemy, managing combat, panic responses, and wandering actions through a behavior tree.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/mushgnomebrain"},{"id":"game-scripts/brains/oceanfishbrain","title":"Oceanfishbrain","description":"Controls the AI behavior of ocean-dwelling fish entities, including feeding, fishing hook interactions, fleeing, and wandering.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/oceanfishbrain"},{"id":"game-scripts/brains/pigguardbrain","title":"Pigguardbrain","description":"Controls the AI behavior of pig guard NPCs, managing combat, navigation, and environmental interactions via a behavior tree.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/pigguardbrain"},{"id":"game-scripts/brains/rabbitbrain","title":"Rabbitbrain","description":"Controls the AI behavior of rabbit-like entities, managing panic responses to predators, home seeking, foraging for edible bait, and wandering.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/rabbitbrain"},{"id":"game-scripts/brains/rabbitking_bunnymanbrain","title":"Rabbitking Bunnymanbrain","description":"Provides AI behavior for rabbit-related minions under the Rabbit King\'s command, implementing movement, aggression, fleeing, and burrowing logic via a behavior tree.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/rabbitking_bunnymanbrain"},{"id":"game-scripts/brains/rabbitkingbrain","title":"Rabbitkingbrain","description":"AI brain component that defines behavioral patterns for the Rabbit King boss, selecting between passive, aggressive, and lucky states based on game context.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/rabbitkingbrain"},{"id":"game-scripts/brains/rockybrain","title":"Rockybrain","description":"AI brain controlling Rocky the Beefalo, managing combat behavior, shield usage, leadership loyalty, and movement strategies including wandering, chasing, and eating.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/rockybrain"},{"id":"game-scripts/brains/shadowheart_infusedbrain","title":"Shadowheart Infusedbrain","description":"Provides AI behavior for shadowheart-infused entities by prioritizing fleeing from players over standing still.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/shadowheart_infusedbrain"},{"id":"game-scripts/brains/shadowthrall_mouth_brain","title":"Shadowthrall Mouth Brain","description":"Controls the AI behavior for the Shadowthrall Mouth entity, managing transitions between combat, idle, and stealth states using a behavior tree.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/shadowthrall_mouth_brain"},{"id":"game-scripts/brains/shadowwaxwellbrain","title":"Shadowwaxwellbrain","description":"Controls AI behavior for Shadow Waxwell minions (e.g., shadowworker, shadowprotector, shadowduelist) by managing priority-based behavior trees focused on following, dancing, avoiding danger, performing work, and combat.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/shadowwaxwellbrain"},{"id":"game-scripts/brains/sharkboi_waterbrain","title":"Sharkboi Waterbrain","description":"Defines the behavior tree for the Sharkboi entity when submerged in water, primarily using a simple wander task.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/sharkboi_waterbrain"},{"id":"game-scripts/brains/slurperbrain","title":"Slurperbrain","description":"Provides AI behavior for the Slurper character by managing behavior tree execution, including panic responses, combat, and homing to a known location.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/slurperbrain"},{"id":"game-scripts/brains/slurtlesnailbrain","title":"SlurtleSnailbrain","description":"Implements AI behavior for the Slurtle Snail entity, including threat avoidance, food seeking, stealing, shield usage, and returning home when hungry.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/slurtlesnailbrain"},{"id":"game-scripts/brains/smallbirdbrain","title":"Smallbirdbrain","description":"Controls the AI behavior of small birds, prioritizing survival (starvation, food), following leaders, evading players when not companions, and engaging in combat when necessary.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/smallbirdbrain"},{"id":"game-scripts/brains/sporebrain","title":"Sporebrain","description":"Manages the AI behavior tree for spore-based entities by combining wandering and follow logic to track nearby characters.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/sporebrain"},{"id":"game-scripts/brains/stagehandbrain","title":"Stagehandbrain","description":"Implements AI behavior for the Stagehand entity, prioritizing panic responses at night while seeking nearby light sources.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/stagehandbrain"},{"id":"game-scripts/brains/stalker_minionbrain","title":"Stalker Minionbrain","description":"Controls the behavior and death timing of stalker minions, ensuring they remain leashed to the stalker, idle while near it, and die after a delay following the stalker\'s death.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/stalker_minionbrain"},{"id":"game-scripts/brains/storage_robotbrain","title":"Storage Robotbrain","description":"Manages the decision-making logic for storage robots to pick up, store, and return items based on inventory state and fuel levels.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/storage_robotbrain"},{"id":"game-scripts/brains/toadstoolbrain","title":"Toadstoolbrain","description":"Implements the behavior tree for the Toadstool entity, managing its channeling, homing, combat engagement, and fleeing states using custom logic and behavior nodes.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/toadstoolbrain"},{"id":"game-scripts/brains/wagstaff_npcbrain","title":"Wagstaff Npcbrain","description":"Controls the behavior tree and state machine of the Wagstaff NPC, managing quest progression, clue-following, arena interactions, and dialogue triggers across different game contexts.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/wagstaff_npcbrain"},{"id":"game-scripts/brains/walrusbrain","title":"Walrusbrain","description":"Controls the decision-making logic and behavior tree for the walrus entity, managing movement, combat, following, and home-seeking behaviors.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/walrusbrain"},{"id":"game-scripts/brains/werepigbrain","title":"Werepigbrain","description":"Manages AI behavior for Werepigs, including panic responses, food-seeking when safe, combat aggression, and wandering with home-based navigation.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/werepigbrain"},{"id":"game-scripts/brains/wobybigbrain","title":"Wobybigbrain","description":"Controls the decision-making behavior of Woby (Walter\'s Woby), including following, combat avoidance, assisting with CHOP/MINE tasks, and interacting with players and the player link UI.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/wobybigbrain"},{"id":"game-scripts/brains/wormwood_carratbrain","title":"Wormwood Carratbrain","description":"AI behavior tree controller that governs Carrat movement and interaction with the environment and leader in Don\'t Starve Together.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/wormwood_carratbrain"},{"id":"game-scripts/brains/wormwood_fruitdragonbrain","title":"Wormwood Fruitdragonbrain","description":"AI brain component for the Wormwood Fruit Dragon entity that manages its movement and combat behavior using a behavior tree.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/wormwood_fruitdragonbrain"},{"id":"game-scripts/brains/wormwood_lightflierbrain","title":"Wormwood Lightflierbrain","description":"Controls the behavior tree logic for the Wormwood Lightflier entity, primarily managing panic responses and walk speed adjustments via the locomotor component.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/wormwood_lightflierbrain"},{"id":"game-scripts/brains/wx78_scannerbrain","title":"Wx78 Scannerbrain","description":"AI behavior controller for the Wx78 Scanner that manages scanning target tracking, following, and return-to-player logic.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/wx78_scannerbrain"}],"unlisted":false}}')}}]);